# Generated by scripts/build_workflow.py — do not edit here.
# Edit src/shiva_agent/review.py and shiva.config.yml, then regenerate.
CATEGORIES = [
  {
    "name": "Structural Review",
    "prompt": "Focus on the architecture and design of the code. Ensure that the code is organized logically and follows best practices for structure."
  },
  {
    "name": "Logical Review",
    "prompt": "Examine the logic and algorithms used in the code. Check for correctness and efficiency of the implemented logic."
  },
  {
    "name": "Behavioral Review",
    "prompt": "Look at how the code behaves in different scenarios. Ensure that the code meets the functional requirements and handles edge cases properly."
  },
  {
    "name": "Security Review",
    "prompt": "Examine the code for potential security vulnerabilities. Ensure that the code follows best practices for security and data protection."
  },
  {
    "name": "Performance Review",
    "prompt": "Analyze the code for performance issues. Ensure that the code is optimized for speed and resource usage."
  }
]

ALLOWED_EXTENSIONS = None  # e.g. [".py"] to review Python files only
DEFAULT_MAX_PATCH_CHARS = 15_000

def filter_files(files, allowed_extensions=None, max_patch_chars=DEFAULT_MAX_PATCH_CHARS):
    """Filter GitHub /pulls/{n}/files items down to reviewable ones.

    Drops files without a patch (binary), removed files, oversized patches,
    and — when allowed_extensions is given — files with other extensions.
    """
    kept = []
    for f in files:
        patch = f.get("patch")
        if not patch:
            continue
        if f.get("status") == "removed":
            continue
        if len(patch) > max_patch_chars:
            continue
        if allowed_extensions is not None:
            name = f.get("filename", "")
            if not any(name.endswith(ext) for ext in allowed_extensions):
                continue
        kept.append(f)
    return kept

def build_review_prompt(categories, files):
    """Assemble the LLM review prompt from enabled categories and file diffs."""
    lines = [
        "You are a code review agent. Review the pull request diff below.",
        "Evaluate the changes ONLY against the following review categories:",
        "",
    ]
    for c in categories:
        lines.append("## " + c["name"])
        lines.append(c["prompt"])
        lines.append("")
    lines.append(
        "For each finding, state the category, the file, the relevant lines, "
        "a severity (high/medium/low), and a short actionable explanation. "
        "If a category has no findings, say so in one line. "
        "Format the whole answer as GitHub-flavored markdown."
    )
    lines.append("")
    lines.append("# Diff")
    if not files:
        lines.append("No reviewable files in this pull request.")
    for f in files:
        lines.append("## " + f.get("filename", "<unknown>") + " (" + f.get("status", "modified") + ")")
        lines.append("```diff")
        lines.append(f.get("patch", ""))
        lines.append("```")
    return "\n".join(lines)


files = [dict(item.json) for item in _input.all()]
kept = filter_files(files, allowed_extensions=ALLOWED_EXTENSIONS)
prompt = build_review_prompt(CATEGORIES, kept)
return [{"json": {"prompt": prompt, "reviewed_files": len(kept), "total_files": len(files)}}]
